// MEGA DATA COLLECTOR — All signals in one object
const revenue = $('Read Revenue').all();
const content = $('Read Content').all();
const patterns = $('Read Patterns').all();
const pastDecisions = $('Read Past Decisions').all();
const competitors = $('Read Competitor Intel').all();

// === REVENUE ===
const totalCustomers = revenue.length;
const totalRevenue = revenue.reduce((sum, r) => sum + (r.json.amount || 350), 0);
const target = 1500;
const remaining = target - totalCustomers;
const avgTicket = totalCustomers > 0 ? Math.round(totalRevenue / totalCustomers) : 0;

// Revenue by source
const sources = {};
revenue.forEach(r => {
  const src = r.json.source || 'organic';
  sources[src] = (sources[src] || 0) + 1;
});

// === CONTENT ===
const totalVideos = content.length;
const publishedLast24h = content.filter(c => {
  const pub = new Date(c.json.published_at || 0);
  return (Date.now() - pub) < 24 * 60 * 60 * 1000;
}).length;
const avgScore = content.length > 0
  ? Math.round(content.reduce((s, c) => s + (c.json.performance_score || 0), 0) / content.length)
  : 0;
const topVideos = content.filter(c => (c.json.performance_score || 0) >= 70);
const deadVideos = content.filter(c => (c.json.performance_score || 0) <= 30);
const totalDMs = content.reduce((s, c) => s + (c.json.dms_generated || 0), 0);
const totalViews = content.reduce((s, c) => s + (c.json.views || 0), 0);

// Best performing hook type
const hookScores = {};
content.forEach(c => {
  const hook = c.json.ab_tag || c.json.hook_type || 'unknown';
  if (!hookScores[hook]) hookScores[hook] = { total: 0, count: 0 };
  hookScores[hook].total += (c.json.performance_score || 0);
  hookScores[hook].count++;
});
let bestHook = { name: 'none', avg: 0 };
Object.entries(hookScores).forEach(([name, data]) => {
  const avg = data.total / data.count;
  if (avg > bestHook.avg) bestHook = { name, avg: Math.round(avg) };
});

// === CONVERSION ===
const conversionRate = totalDMs > 0 ? (totalCustomers / totalDMs * 100) : 0;
const viewToConversion = totalViews > 0 ? (totalCustomers / totalViews * 100) : 0;

// === PATTERNS ===
const scalePatterns = patterns.filter(p => p.json.result === 'SCALE').length;
const killPatterns = patterns.filter(p => p.json.result === 'KILL').length;
const winRate = patterns.length > 0 ? (scalePatterns / patterns.length * 100) : 0;

// === TIME ===
const deadline = new Date('2026-04-05T23:59:59');
const now = new Date();
const hoursLeft = Math.max(0, Math.round((deadline - now) / (1000 * 60 * 60)));
const daysLeft = Math.round(hoursLeft / 24);
const customersPerDay = daysLeft > 0 ? (remaining / daysLeft) : remaining;

// === PAST DECISIONS ===
const recentDecisions = pastDecisions.slice(0, 5).map(d => ({
  action: d.json.action || '',
  result: d.json.outcome || 'pending',
  confidence: d.json.confidence || 0
}));
const avgConfidence = recentDecisions.length > 0
  ? Math.round(recentDecisions.reduce((s, d) => s + d.confidence, 0) / recentDecisions.length)
  : 0;
const successRate = recentDecisions.filter(d => d.result === 'success').length / Math.max(1, recentDecisions.length) * 100;

// === COMPETITORS ===
const competitorSummary = competitors.slice(0, 3).map(c => ({
  name: c.json.name || '',
  price: c.json.price || 0,
  followers: c.json.followers || 0,
  lastMove: c.json.last_move || ''
}));

return {
  json: {
    revenue: { totalCustomers, totalRevenue, remaining, target, avgTicket, sources },
    content: { totalVideos, publishedLast24h, avgScore, topVideos: topVideos.length, deadVideos: deadVideos.length, bestHook, totalViews },
    dms: { totalDMs, conversionRate: conversionRate.toFixed(1), viewToConversion: viewToConversion.toFixed(2) },
    patterns: { scalePatterns, killPatterns, winRate: winRate.toFixed(1) },
    time: { hoursLeft, daysLeft, customersPerDay: customersPerDay.toFixed(1) },
    learning: { recentDecisions, avgConfidence, successRate: successRate.toFixed(1) },
    competitors: competitorSummary,
    timestamp: now.toISOString()
  }
};

