// Parse Claude's response and structure decisions
const response = $input.item.json;
let brainOutput;

try {
  // Extract JSON from Claude's response
  const content = response.content?.[0]?.text || response.body || '{}';
  // Try to parse, handle if wrapped in markdown code block
  let jsonStr = content;
  if (jsonStr.includes('```json')) {
    jsonStr = jsonStr.split('```json')[1].split('```')[0].trim();
  } else if (jsonStr.includes('```')) {
    jsonStr = jsonStr.split('```')[1].split('```')[0].trim();
  }
  brainOutput = JSON.parse(jsonStr);
} catch (e) {
  brainOutput = {
    decisions: [{
      id: 'd1',
      action: 'خطأ في تحليل العقل — تحقق يدوياً',
      target_agent: 'borhan',
      priority: 'high',
      confidence: 0,
      reason: 'فشل parsing: ' + e.message,
      expected_impact: 'none',
      risk: 'high',
      deadline_hours: 1
    }],
    pricing: { current: 350, recommended: 350, reason: 'خطأ', scarcity_message: '' },
    content_strategy: { best_hook_type: 'unknown', produce_count: 3, angles: [], kill_list: [] },
    overall_status: 'warning',
    one_line_summary: 'خطأ في التحليل — مراجعة يدوية مطلوبة'
  };
}

// Get original data from Mega Data Collector
const originalData = $('Mega Data Collector').item.json;

// Add metadata
brainOutput.meta = {
  timestamp: new Date().toISOString(),
  data_snapshot: {
    customers: originalData.revenue.totalCustomers,
    revenue: originalData.revenue.totalRevenue,
    dms: originalData.dms.totalDMs,
    days_left: originalData.time.daysLeft
  },
  decisions_count: brainOutput.decisions?.length || 0,
  critical_count: (brainOutput.decisions || []).filter(d => d.priority === 'critical').length
};

return { json: brainOutput };

